import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt0701.jpg",d="/images/lekt0704.jpg",s="/images/lekt0702.jpg",u="/images/lekt0703.jpg",g=JSON.parse('{"title":"Lektion 7","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion07.md","filePath":"lektionen/lektion07.md"}'),l={name:"lektionen/lektion07.md"};function h(p,t,m,o,k,b){return a(),r("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-7" tabindex="-1">Lektion 7 <a class="header-anchor" href="#lektion-7" aria-label="Permalink to &quot;Lektion 7&quot;">​</a></h1><h3 id="wochenspruch" tabindex="-1">Wochenspruch <a class="header-anchor" href="#wochenspruch" aria-label="Permalink to &quot;Wochenspruch&quot;">​</a></h3><p>धर्मो जयति नधर्मः<br> सत्यं जयति नानृतम् |<br> क्षमा जयति न क्रोधो<br> देवो जयति नासुरः ||</p><p>dharmo jayati nādharmaḥ<br> satyaṃ jayati nānṛtam |<br> kṣamā jayati na krodho<br> devo jayati nāsuraḥ ||</p><p>Das Recht siegt nicht das Unrecht,<br> Die Wahrheit siegt, nicht die Unwahrheit,<br> Nachsicht siegt nicht Zorn,<br> Gott siegt, nicht der Widergott.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Wochenspruch</p><ul><li>7.1. Der Verbalsatz mit direktem Objekt</li><li>7.2. Der Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;) <ul><li>7.2.1. Akkusativ singular und Plural der Frage- und Demonstrativpronomina</li><li>7.2.2. Gebrauch des Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;)</li></ul></li><li>7.3. Sandhi von auslautendem -n</li><li>7.4. Das Neutrum (napuṃsaka n. =  नपुंसक) <ul><li>7.4.1. Neutrum der Stämme auf -a</li></ul></li><li>7.5. Athematische Präsensklassen <ul><li>7.5.1. Primärendungen der 3. Person Plural bei athematischen Präsensstämmen</li><li>7.5.2. Die 5. Präsensklasse (svādi = स्वादि = &quot;su usw.&quot;</li></ul></li><li>7.6. Wortliste</li><li>7.7. Übung</li></ul><h2 id="_7-1-der-verbalsatz-mit-direktem-objekt" tabindex="-1">7.1. Der Verbalsatz mit direktem Objekt <a class="header-anchor" href="#_7-1-der-verbalsatz-mit-direktem-objekt" aria-label="Permalink to &quot;7.1. Der Verbalsatz mit direktem Objekt&quot;">​</a></h2><p>| Schema: (Agens = kartṛ m. = कर्तृ) - direktes Objekt (karman n. = कर्मन्) - Verb</p><p>z.B.</p><p>rāmaḥ phalaṃ khādati = रामः फलं खदति = &quot;Rāma isst (kaut) eine Frucht.&quot;</p><p>brāhmaṇo devaṃ yajati =  ब्राह्मणो देवं यजति = &quot;Der (ein) Brahmane verehrt einen Gott mit einem Opfer (für jemand anderes):&quot;</p><p>| | --- | | Steht das Verb im Parasmaipada oder Ātmanepada, so steht das direkte Objekt (karman n. = कर्मन्) im Allgemeinen im Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;). |</p><h2 id="_7-2-der-akkusativ-wenfall-dvitiya-f-द्वितीया-zweite-kasusendung" tabindex="-1">7.2. Der Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;) <a class="header-anchor" href="#_7-2-der-akkusativ-wenfall-dvitiya-f-द्वितीया-zweite-kasusendung" aria-label="Permalink to &quot;7.2. Der Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;)&quot;">​</a></h2><table><tbody><tr><td colspan="2">**<br>Endung des Akkusativ singular maskulinum und femininum nach Vokal: -m<br> **</td></tr><tr><th>Maskulina auf</th><th>Akkusativ singular</th></tr><tr><th>-a: deva</th><th>devam<br>देवम्</th></tr><tr><th>-i: kavi</th><th>kavim<br>कविम्</th></tr><tr><th>-u: guru</th><th>gurum<br>गुरुम्</th></tr><tr><th>Feminina auf</th><th></th></tr><tr><th>-ā: devatā</th><th>devatām<br>देवताम्</th></tr><tr><th>-i: śruti</th><th>śrutim<br>श्रुतिम्</th></tr><tr><th>-ī: devī</th><th>devīm<br>देवीम्</th></tr><tr><th>-u: dhenu</th><th>dhenum<br>धेनुम्</th></tr><tr><th></th><th></th></tr><tr><th colspan="2"><br>Akkusativ plural maskulinum der Stämme auf Vokal (Ausnahme: einsilbige Wurzelstämme auf langen Vokal):<br>Längung des auslautenden Vokals + -n<br></th></tr><tr><th>Maskulina auf</th><th>Akkusativ plural</th></tr><tr><th>-a: deva</th><th>devān<br>देवान्</th></tr><tr><th>-i: kavi</th><th>kavīn<br>कवीन्</th></tr><tr><th>-u: guru</th><th>gurūn<br>गुरून्</th></tr><tr><th></th><th></th></tr><tr><th colspan="2"><br>Akkusativ plural femininum der Stämme auf Vokal (Ausnahme: einsilbige Wurzelstämme auf langen Vokal):<br>Längung des auslautenden Vokals + -s<br></th></tr><tr><th>Feminina auf</th><th>Akkusativ plural</th></tr><tr><th>-ā: devatā</th><th>devatās<br>देवतास्</th></tr><tr><th>-i: śruti</th><th>śrutīs<br>श्रुतीस्</th></tr><tr><th>-ī: devī</th><th>devīs<br>देवीस्</th></tr><tr><th>-u: dhenu</th><th>dhenūs<br>धेनूस्</th></tr></tbody></table><h3 id="_7-2-1-akkusativ-singular-und-plural-der-frage-und-demonstrativpronomina" tabindex="-1">7.2.1. Akkusativ singular und Plural der Frage- und Demonstrativpronomina <a class="header-anchor" href="#_7-2-1-akkusativ-singular-und-plural-der-frage-und-demonstrativpronomina" aria-label="Permalink to &quot;7.2.1. Akkusativ singular und Plural der Frage- und Demonstrativpronomina&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th><th>Akkusativ</th></tr></thead><tbody><tr><td></td><td></td><td>Maskulinum</td></tr><tr><td>kim</td><td></td><td></td></tr><tr><td>किम्</td><td>sg.</td><td>kam</td></tr><tr><td>कम्</td><td>kām</td><td></td></tr><tr><td>काम्</td><td>kim</td><td></td></tr><tr><td>किम्</td><td></td><td></td></tr><tr><td></td><td>pl.</td><td>kān</td></tr><tr><td>कान्</td><td>kās</td><td></td></tr><tr><td>कास्</td><td>kāni</td><td></td></tr><tr><td>कानि</td><td></td><td></td></tr><tr><td>tad</td><td></td><td></td></tr><tr><td>तद्</td><td>sg.</td><td>tam</td></tr><tr><td>तम्</td><td>tām</td><td></td></tr><tr><td>ताम्</td><td>tad</td><td></td></tr><tr><td>तद्</td><td></td><td></td></tr><tr><td></td><td>pl.</td><td>tān</td></tr><tr><td>तान्</td><td>tās</td><td></td></tr><tr><td>तास्</td><td>tāni</td><td></td></tr><tr><td>तानि</td><td></td><td></td></tr><tr><td>etad</td><td></td><td></td></tr><tr><td>एतद्</td><td>sg.</td><td>etaम् / enam</td></tr><tr><td>एतम् /एनम्</td><td>etām / enām</td><td></td></tr><tr><td>एताम् / एनाम्</td><td>etad / enad</td><td></td></tr><tr><td>एतद् / एनद्</td><td></td><td></td></tr><tr><td></td><td>pl.</td><td>etān / enān</td></tr><tr><td>एतान् / एनान्</td><td>etās / enās</td><td></td></tr><tr><td>एतास् / एनास्</td><td>etāni / enāni</td><td></td></tr><tr><td>एतानि / एनानि</td><td></td><td></td></tr><tr><td>idam</td><td></td><td></td></tr><tr><td>इदम्</td><td>sg.</td><td>imam / enam</td></tr><tr><td>इमम् &amp; एनम्</td><td>imām / enām</td><td></td></tr><tr><td>इमाम् / एनाम्</td><td>idam / enad</td><td></td></tr><tr><td>इदम् / एनद्</td><td></td><td></td></tr><tr><td></td><td>pl.</td><td>imān / enān</td></tr><tr><td>इमान् / एनान्</td><td>imās /enās</td><td></td></tr><tr><td>इमास् / एनास्</td><td>imāni / enāni</td><td></td></tr><tr><td>इमानि / एनानि</td><td></td><td></td></tr></tbody></table><p>Die Formen enam ) एनम् usw. gehören zum Stamm enad = एनद्, der nur in einigen Kasus Formen bildet. In den Kasus, in denen Formen dieses Stammes vorkommen, werden diese statt der Formen von etad =  एतद्  und idam = इदम्  dann verwendet, wenn das damit Bezeichnete im Vorhergehenden bereits erwähnt wurde. z.B. ayaṃ devaḥ, enaṃ yajante. = अयं देवः | एनं यजन्ते || = &quot;Er ist ein Gott. Man opfert ihm.&quot;</p><h3 id="_7-2-2-gebrauch-des-akkusativ-wenfall-dvitiya-f-द्वितीया-zweite-kasusendung" tabindex="-1">7.2.2. Gebrauch des Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;) <a class="header-anchor" href="#_7-2-2-gebrauch-des-akkusativ-wenfall-dvitiya-f-द्वितीया-zweite-kasusendung" aria-label="Permalink to &quot;7.2.2. Gebrauch des Akkusativ (Wenfall, dvitīyā f. = द्वितीया = &quot;zweite Kasusendung&quot;)&quot;">​</a></h3><p>Der Akkusativ (dvitīyā f. = द्वितीया) bezeichnet:</p><ol><li>im nicht passiven-Verbalsatz: das direkte Objekt (karman n. = कर्मन्) der durch das Verb ausgedrückten Handlung:<br> z.B.<br> devaṃ yajati = देवं यजति = &quot;Er verehrt einen Gott mit einem Opfer.&quot;<br> phalam āpnoti =  फलमाप्नोति = &quot;Er erlangt die Frucht (z.B. seines Handelns).&quot;</li><li>bei Verbe, die ein Gehen, eine Bewegung, ein Führen oder dergl. nach etwas hin ausdrücken, bezeichnet der Akkusativ das Ziel der Bewegung:<br> z.B.<br> narakaṃ gacchati =  नरकं गच्चति = &quot;Er geht zur Hölle.&quot;</li></ol><p>Weitere Verwendungen des Akkusativ werden später behandelt.</p><h2 id="_7-3-sandhi-von-auslautendem-n" tabindex="-1">7.3. Sandhi von auslautendem -n <a class="header-anchor" href="#_7-3-sandhi-von-auslautendem-n" aria-label="Permalink to &quot;7.3. Sandhi von auslautendem -n&quot;">​</a></h2><p>Auslautendes -n</p><ol><li><p>wird vor stimmhaften palatalen und retroflexen sparśa und vor ś- durch den diesen Lauten entsprechenden Nasal ersetzt:</p><ul><li>-n vor j-, jh-, ñ-, ś- » -ñ</li><li>-n vor ḍ-, ḍh-, ṇ-, ṣ- » -ṇ</li></ul><p>z.B.<br> kṣatriyān + jayati » kṣatriyāñ jayati = क्शत्रियाञ्जयति = &quot;Er besiegt die Katriyas.&quot;</p><p>Anlautendes ś- wird dann meist durch ch- ersetzt<br> z.B. gurūn + śrṇoti » gurūñ chṛṇoti (neben: gurūñ śṛnoti) = गुरूञ्छृणोति (गुरूञ्शृणोति) = &quot;Er hört die Lehrer.&quot; &quot;Er hört auf die Lehrer.&quot;</p></li><li><p>wird vor anlautendem l- durch -लँ  (nasaliertes l, in der Schrift ल् mit Anunāsika ँ ) ersetzt:<br> z.B.<br> paśūn + labhate » पशूल्ंलभते = &quot;Er erhält Nutztiere.&quot;</p></li><li><p>wird vor anlautendem stimmlosen Palatal, Retroflex oder Dental durch Anusvāra + dem diesen Lauten entsprechenden Zischlaut ersetzt:</p><ul><li>-n vor c-, ch- » -ṃś</li><li>-n vor ṭ-, ṭh- » -ṃṣ</li><li>-n vor t-, th- » -ṃs</li></ul><p>z.B.<br> devān + ca » devāṃś ca = देवांश्च = &quot;und die Götter (Akk.)&quot;<br> devān + tu » devāṃs tu = देवांस्तु = &quot;aber die Götter (Akk.)&quot;</p></li><li><p>außer nach kurzem Vokal (siehe später) bleibt auslautendes -n in allen übrigen Fällen unverändert</p></li></ol><h2 id="_7-4-das-neutrum-napumsaka-n-नपुंसक" tabindex="-1">7.4. Das Neutrum (napuṃsaka n. =  नपुंसक) <a class="header-anchor" href="#_7-4-das-neutrum-napumsaka-n-नपुंसक" aria-label="Permalink to &quot;7.4. Das Neutrum (napuṃsaka n. =  नपुंसक)&quot;">​</a></h2><p>Im Neutrum sind die Formen für Nominativ (prathamā) und Akkusativ (dvitīyā) identisch.</p><h3 id="_7-4-1-neutrum-der-stamme-auf-a" tabindex="-1">7.4.1. Neutrum der Stämme auf -a <a class="header-anchor" href="#_7-4-1-neutrum-der-stamme-auf-a" aria-label="Permalink to &quot;7.4.1. Neutrum der Stämme auf -a&quot;">​</a></h3><p>| Endung des Nominativ / Akkusativ singular: -m z.B. phala n. = फल = &quot;Frucht&quot;: Nom. / Akk. sg. phalam = फलम्</p><p>| | --- | | Endung des Nominativ / Akkusativ plural: -āni</p><p>z.B. z.B. phala n. = फल: Nom. / Akk. pl. phalāni =  फलानि</p><p>|</p><h2 id="_7-5-athematische-prasensklassen" tabindex="-1">7.5. Athematische Präsensklassen <a class="header-anchor" href="#_7-5-athematische-prasensklassen" aria-label="Permalink to &quot;7.5. Athematische Präsensklassen&quot;">​</a></h2><p>Die 5. Präsensklasse bildet einen sogenannten athematischen Präsensstamm, d.h. der Präsensstamm lautet nicht wie bei den thematischen Präsensklassen (1., 4., 6., 10. Klasse) auf den &quot;Themavokal&quot; -a aus.</p><p>Die athematischen Präsensklassen haben Stammabstufung, d.h. es gibt zwei Formen des Präsensstamms:</p><ol><li>starker Stamm: hochstufig (selten dehnstufig)</li><li>schwacher Stamm: tiefstufig</li></ol><p>Der starke Stamm steht:</p><ol><li>im Indikativ Singular Parasmaipada Präsens (laṭ) und Imperfekt (laṅ)</li><li>allen ersten Personen des Imperativ (loṭ) Parasmaipada und Ātmanepada</li><li>in der dritten Person Singular Imperativ (loṭ) Parasmaipada</li></ol><p>Alle anderen Formen haben den schwachen Präsensstamm.</p><h3 id="_7-5-1-primarendungen-der-3-person-plural-bei-athematischen-prasensstammen" tabindex="-1">7.5.1. Primärendungen der 3. Person Plural bei athematischen Präsensstämmen <a class="header-anchor" href="#_7-5-1-primarendungen-der-3-person-plural-bei-athematischen-prasensstammen" aria-label="Permalink to &quot;7.5.1. Primärendungen der 3. Person Plural bei athematischen Präsensstämmen&quot;">​</a></h3><p>Bei athematischen Präsensstämmen lauten die Primärendungen der 3. Person Plural:</p><ul><li>Parasmaipada: -anti</li><li>Ātmanepada: -ate</li></ul><h3 id="_7-5-2-die-5-prasensklasse-svadi-स्वादि-su-usw" tabindex="-1">7.5.2. Die 5. Präsensklasse (svādi = स्वादि = &quot;su usw.&quot; <a class="header-anchor" href="#_7-5-2-die-5-prasensklasse-svadi-स्वादि-su-usw" aria-label="Permalink to &quot;7.5.2. Die 5. Präsensklasse (svādi = स्वादि = &quot;su usw.&quot;&quot;">​</a></h3><p>Starker Stamm: (meist) tiefstufige Wurzel (wie angeführt) + -no-</p><p>Schwacher Stamm:  (meist) tiefstufige Wurzel (wie angeführt) + -nu-</p><p>Vor vokalischen Endungen wird bei vokalisch auslautenden Wurzeln -nu- durch -nv- ersetzt, bei konsonantisch auslautenden Wurzeln wird vor vokalischen Endungen -nu- durch -nuv- ersetzt.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>Starker Stamm</th><th>Schwacher Stamm</th><th>Schwacher Stamm vor Vokal</th></tr></thead><tbody><tr><td>āp 5 P</td><td></td><td></td><td></td></tr><tr><td>आप्</td><td></td><td></td><td></td></tr><tr><td>&quot;erreichen, erlangen&quot;</td><td>āp-no</td><td></td><td></td></tr><tr><td>3.sg.P. āp-no-ti</td><td></td><td></td><td></td></tr><tr><td>आप्नोति</td><td></td><td></td><td></td></tr></tbody></table><p>| āp-nu | āp-nuv</p><p>3.pl.P. āp-nuv-anti<br> आप्नुवन्ति</p><p>| | aś 5 Ā<br> अश्<br> &quot;erreichen, erlangen&quot; |   | aś-nu</p><p>3.sg.Ā. aś-nu-te<br> अश्नुते</p><p>| aś-nuv</p><p>3.pl.Ā. aś-nuv-ate<br> अश्नुवते</p><p>| | su 5 U<br> सु<br> &quot;auspressen&quot; | su-no</p><p>3.sg.P. su-no-ti<br> सुनोति</p><p>| su-nu</p><p>3.sg.Ā. su-nu-te<br> सुनुते</p><p>| su-nv</p><p>3.pl.P. su-nv-anti<br> सुन्वन्ति<br> 3. pl.Ā. su-nv-ate<br> सुन्वते</p><p>| | Beachten Sie:</p><p>śru 5 P<br> श्रु<br> &quot;hören&quot;</p><p>| śṛ-ṇo</p><p>3.sg.P. śṛ-ṇo-ti<br> शृणोति</p><p>(das ṇ statt ṇ ist regelmäßiger<br> Wortsandhi, siehe später)</p><p>| śṛ-ṇu | śṛ-ṇv</p><p>3.pl.P. śṛ-ṇv-anti<br> शृण्वन्ति</p><p>|</p><h2 id="_7-6-wortliste" tabindex="-1">7.6. Wortliste <a class="header-anchor" href="#_7-6-wortliste" aria-label="Permalink to &quot;7.6. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>aś 5 Ā (aśnute) अश् अश्नुते : erreichen, gelangen zu, erlangen</p><p>āp 5 P (āpnoti) आप् आप्नोति : erreichen, erlangen</p><p>kup 4 P (kupyati) कुप् कुप्यति : zürnen</p><p>krudh 4 P (krudhyati) क्रुध् क्रुध्यति : zürnen</p><p>khād 1 P (khādati) खाद् खादति : kauen, essen</p><p>śru 5 P (śṛṇoti !) श्रु शृणोति : hören (etwas: Akkusativ, jemanden: Genetiv oder Akkusativ; über: Akkusativ; von jemandem: Genetiv, Ablativ, Instrumentalis)</p><p>su 5 U (sunoti) सु सुनोति : auspressen</p><p>soma m. सोम : Presstrank, Soma; Mond (Aus welcher Pflanze Soma gepresst wurde, ist bis heute umstritten).</p><p><img src="'+i+'" alt=""><br> Abb.: War das die vedische Somapflanze?: Fliegenpilz: <em>Amanita muscaria</em> (L.) Lam.<br> [Bildquelle: Wikipedia, GNU FDLizenz]</p><p>phala n. फल : Frucht (auch im übertragenen Sinn: (karmische) Frucht einer Tat)</p><p>nṛtya n. नृत्य : Tanz</p><p>svarga m. स्वर्ग : Himmel</p><p>naraka m. नरक : Hölle (nach einer Hinduauffassung hat das Universum die Form eines Eis (Brahmāṇḍa m.n. ) ब्रह्माण्ड = &quot;Ei Brahmā&#39;s): oberhalb der Erde sind sechs Himmel mit ansteigender Glückseligkeit, unterhalb der Erde sind sieben sog. pātāla n. ) पाताल, Wohnstätten der nāga m. ) नाग (Schlangen) und anderer mythischer wesen, darunter kommen 7 Höllen mit steigenden Qualen)</p><p>aṅga n. अङ्ग : Glied des Körpers, Bestandteil; auch = vedāṅga = वेदाङ्ग</p><p>gam 1 P (gacchati) गम् गच्छति : gehen (Gehört nach der einheimischeb Verbklassifikation zur Präsensklasse 1, ist aber in Wirklichkeit eine Bildung mit einem Präsensstammbildungssuffix -ccha-: gam » Tiefstufe (gm ») ga-ccha-ti)</p><h2 id="_7-7-ubung" tabindex="-1">7.7. Übung <a class="header-anchor" href="#_7-7-ubung" aria-label="Permalink to &quot;7.7. Übung&quot;">​</a></h2><p>A) Setzen Sie jeweils im Singular und Plural (sofern es keine Eigennamen sind) das direkte Objekt bzw. den Richtungsakkusativ ein:</p><p>1. brāhmaṇas ... yajati (deva, devī, viṣṇu, agni, devatā)</p><p>ब्राह्मणस् ... यजति (देव, देवी, विष्णु, अग्नि, देवता)</p><p><img src="'+d+'" alt=""><br> Abb.: Viṣṇu = विष्णु, 8./9. Jhdt.<br> [Bildquelle: Wikipedia, GNU FDLizenz]</p><p>2. gurus ... khādati (phala)</p><p>गुरुस् ... खादति (फल)</p><p>3. sādhus ... gacchati (svarga)</p><p>साधुस् ... गच्छति (स्वर्ग)</p><p>4. śūdrā ... gacchati (naraka)</p><p>शूद्रा ... गच्छति (नरक)</p><p>5. ... jayati (śūdra)</p><p>... जयति (शूद्र)</p><p>6. ... labhate (dhenu, paśu, phala)</p><p>... लभते (धेनु, पशु, फल)</p><p>B) Setzen Sie dien entsprechenden Verbformen ein:</p><p>1. sādhuḥ svargam ... (āp, gam, aś)</p><p>साधुः स्वर्गम् ... (आप्, गम्, अश्)</p><p>2. brāhmaṇaḥ somam ... (su) (2 Formen)</p><p>ब्राह्मणः सोमम् ... (सु)</p><p>3. sādhur gurum ... (śru)</p><p>साधुर्गुरुम् ... (श्रु)</p><p>4. devī ... (kup, krudh)</p><p>देवी ... (कुप्, क्रुध्)</p><p>C) Setzen Sie in den Übungssätzen B) Agens, Objekt und Verb in den Plural.</p><p>D) Setzen Sie ins Ātmanepada:</p><p>1. sunvanti.</p><p>सुन्वन्ति |</p><p>2. nayanti.</p><p>नयन्ति |</p><p>3. sunoti.</p><p>सुनोति |</p><p>4. yajati.</p><p>यजति |</p><p><img src="'+s+'" alt=""><br> Abb.: yajati = यजति<br> Vedisches Opfer = yajna m. = यज्न<br> [Bildquelle: Wikipedia, Public domain]</p><p>E) Bilden Sie zu allen bisher gelernten Nomina den Akkusativ (dvitīyā) sg. und pl.</p><p>F) Übersetzen Sie:</p><p>1. narakāṃś ca svargāṃś ca gacchanti.</p><p>नरकांश्च स्वर्गांश्च गच्छन्ति |</p><p>2. gurūṃs tu śṛṇvanti.</p><p>गुरूंस्तु शृण्वन्ति |</p><p>3. Śūdras erlangen einen Himmel.</p><p>4. Die Kṣatriyas verehren als Opferherren die Göttinnen mit Opfern.</p><p>5. Vaiśyafrauen verehren Gottheiten mit Opfern.</p><p>6. Der HERR zürnt.</p><p>7. śikṣā kalpo vyākaraṇaṃ niruktaṃ chando jyotiṣam aṅgāni. (Nach Kauṭilīya-arthaṣāstra 1.3.3.) Erklärung: chando = Nom,, Akk. sg. zu chandas n.)</p><p>शिक्षा कल्पो व्याकरणं निरुक्तं छन्दो ज्योतिषमङ्गानि |</p><p>8. Welchem Gott opfert dieser Brahmane?</p><p><img src="'+u+'" alt=""><br> Abb.: Welchem Gott opfert man hier? -- Antwort: dem Gaṇeśa (Gaṇapati) = गणेश (गणपति)<br> Gaṇapatihoma (Gaṇapatiyajna)<br> [Bildquelle: Rajaramraok, Wikipedia; Creative Commons <a href="http://creativecommons.org/licenses/by/3.0/" title="http://creativecommons.org/licenses/by/3.0/" target="_blank" rel="noreferrer">Attribution 3.0</a> License]</p><p>9. Was kaut dieser heilige Mann?</p><p>10. Was pressen diese (hier) aus?</p><p>11. Er ist der Lehrer. Auf ihn hört man (= hören sie).</p>',139)])])}const v=e(l,[["render",h]]);export{g as __pageData,v as default};
